class Solution:
    def friendRequests(self, n: int, restrictions: List[List[int]], requests: List[List[int]]) -> List[bool]:
        parent = list(range(n))
        rank = [1] * n

        def find(u):
            while parent[u] != u:
                parent[u] = parent[parent[u]]
                u = parent[u]
            return u

        def union(u, v):
            u_root = find(u)
            v_root = find(v)
            if u_root == v_root:
                return
            if rank[u_root] < rank[v_root]:
                parent[u_root] = v_root
            else:
                parent[v_root] = u_root
                if rank[u_root] == rank[v_root]:
                    rank[u_root] += 1

        result = []
        for u, v in requests:
            if find(u) == find(v):
                result.append(True)
                continue
            conflict = False
            for x, y in restrictions:
                if find(x) == find(y):
                    conflict = True
                    break
                if (find(x) == find(u) and find(y) == find(v)) or (find(x) == find(v) and find(y) == find(u)):
                    conflict = True
                    break
            if not conflict:
                union(u, v)
                result.append(True)
            else:
                result.append(False)
        return result

